+import { describe, expect, it } from 'vitest';
+import {
+    createAdded,
+    createChanged,
+    createPredicate,
+    createRemoved,
+    createWorld,
+    Not,
+    Or,
+    relation,
+    trait,
+} from '../src';
+
+const Score = trait({ value: 0 });
+const Bonus = trait({ value: 0 });
+const Tag = trait();
+const Parent = relation();
+
+describe('value predicates', () => {
+    it('filters by dependency values, re-evaluates writes, and omits dependencies from tuples', () => {
+        const world = createWorld();
+        world.init();
+        const highScore = createPredicate([Score, Bonus], ([score, bonus]) => score.value + bonus.value > 10);
+        const entity = world.spawn(Score({ value: 8 }), Bonus({ value: 1 }));
+
+        expect(world.query(highScore)).toEqual([]);
+        entity.set(Bonus, { value: 3 });
+        expect(world.query(highScore)).toEqual([entity]);
+
+        let tupleLength = -1;
+        world.query(highScore).readEach((state) => (tupleLength = state.length));
+        expect(tupleLength).toBe(0);
+
+        entity.set(Score, { value: 1 });
+        expect(world.query(highScore)).toEqual([]);
+        expect(world.query(Not(highScore))).toEqual([entity]);
+    });
+
+    it('supports predicates in Or and relation-pair queries', () => {
+        const world = createWorld();
+        world.init();
+        const highScore = createPredicate([Score], ([score]) => score.value > 10);
+        const parent = world.spawn();
+        const child = world.spawn(Score({ value: 5 }), Parent(parent));
+
+        expect(world.query(Or(highScore, Bonus), Parent(parent))).toEqual([]);
+        child.add(Bonus);
+        expect(world.query(Or(highScore, Bonus), Parent(parent))).toEqual([child]);
+    });
+
+    it('tracks predicate truthiness transitions', () => {
+        const world = createWorld();
+        world.init();
+        const highScore = createPredicate([Score], ([score]) => score.value > 10);
+        const Added = createAdded();
+        const Removed = createRemoved();
+        const Changed = createChanged();
+        const entity = world.spawn(Score({ value: 5 }));
+
+        expect(world.query(Added(highScore))).toEqual([]);
+        expect(world.query(Removed(highScore))).toEqual([]);
+        expect(world.query(Changed(highScore))).toEqual([]);
+
+        entity.set(Score, { value: 11 });
+        expect(world.query(Added(highScore))).toEqual([entity]);
+        expect(world.query(Removed(highScore))).toEqual([]);
+        expect(world.query(Changed(highScore))).toEqual([entity]);
+
+        entity.set(Score, { value: 4 });
+        expect(world.query(Added(highScore))).toEqual([]);
+        expect(world.query(Removed(highScore))).toEqual([entity]);
+        expect(world.query(Changed(highScore))).toEqual([entity]);
+    });
+
+    it('rejects tags and relations as dependencies and creates distinct instances', () => {
+        expect(() => createPredicate([Tag], () => true)).toThrow(/tags or relations/);
+        expect(() => createPredicate([Parent as never], () => true)).toThrow(/tags or relations/);
+        expect(createPredicate([Score], () => true)).not.toBe(createPredicate([Score], () => true));
+    });
+});
